var src='v1';
var lines=msg.payload.split('\n').filter(function(l){return l.trim()!==''});
var recs=[];
for(var i=1;i<lines.length;i++){
  var c=lines[i].split(',');if(c.length<4)continue;
  var v1=parseFloat(c[1]),v2=parseFloat(c[2]),w=parseFloat(c[3]);
  if(!isNaN(v1)&&!isNaN(v2)&&!isNaN(w))recs.push({var1:v1,var2:v2,w:w});
}
if(!recs.length)return null;
var n=recs.length,sum=0,mn=recs[0].w,mx=recs[0].w;
for(var i=0;i<n;i++){sum+=recs[i].w;
  if(recs[i].w<mn)mn=recs[i].w;
  if(recs[i].w>mx)mx=recs[i].w;}
var mean=sum/n,v=0;
for(var i=0;i<n;i++)v+=(recs[i].w-mean)*(recs[i].w-mean);
var stdev=Math.sqrt(v/n);
var ws=recs.map(function(r){return r.w;}).sort(function(a,b){return a-b;});
var q1=ws[Math.floor(n*0.25)],q3=ws[Math.floor(n*0.75)];
var median=n%2===0?(ws[n/2-1]+ws[n/2])/2:ws[Math.floor(n/2)];
var stats={source:src,n:n,
  mean:parseFloat(mean.toFixed(5)),stdev:parseFloat(stdev.toFixed(5)),
  min:parseFloat(mn.toFixed(5)),max:parseFloat(mx.toFixed(5)),
  median:parseFloat(median.toFixed(5)),
  q1:parseFloat(q1.toFixed(5)),q3:parseFloat(q3.toFixed(5)),
  iqr:parseFloat((q3-q1).toFixed(5))};
var st=Math.max(1,Math.ceil(n/8000)),mnH=recs[0].w,mxH=recs[0].w,hs=[];
for(var i=0;i<n;i+=st){hs.push(recs[i]);
  if(recs[i].w<mnH)mnH=recs[i].w;
  if(recs[i].w>mxH)mxH=recs[i].w;}
var hp=[];
for(var i=0;i<hs.length;i++)
  hp.push({x:hs[i].var1/762,y:hs[i].var2/458,n:(hs[i].w-mnH)/(mxH-mnH+1e-9)});
var mStats={payload:JSON.stringify({type:'stats',label:'Experimento V1',color:'#1565C0',stats:stats})};
var mHeat={payload:JSON.stringify({type:'heat',source:'v1',pts:hp,
  minW:parseFloat(mnH.toFixed(4)),maxW:parseFloat(mxH.toFixed(4))})};
node.status({fill:'green',shape:'dot',text:'v1 listo'});
return [mStats, mHeat];

